it("should return premium 65 G for a single plain amulet — 60 G base + 5 G fee", () => {
  const input = {
    customer: { yearsWithMHPCO: 0 },
    steps: [
      {
        op: "quote" as const,
        items: [
          { type: "amulet", material: "silver", enchantment: 0, cursed: false },
        ],
      },
    ],
  };
  const result = claimOffice(input);
  expect(result).toEqual({ results: [{ premium: 65 }] });
});

